import { type ClassValue, clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

import { differenceInHours, parseISO } from 'date-fns';
import axios from 'axios';

export interface PricingBreakdown {
  basePrice: number;
  basePriceLabel: string;
  earlyDropoffSurcharge: number;
  earlyDropoffLabel: string;
  latePickupFee: number;
  latePickupLabel: string;
  peakPeriodSurcharge: number;
  peakPeriodLabel: string;
  totalPrice: number;
}

export interface PricingInput {
  dropoffDate: string;
  dropoffTime: string;
  pickupDate: string;
  pickupTime: string;
}

interface PricingRule {
  id: string;
  title: string;
  duration: string;
  price: number;
  active: boolean;
  category: 'base' | 'surcharge' | 'addon' | 'peak';
  pricingType: 'flat' | 'daily' | 'hourly';
  description: string;
}

// Cache for pricing rules
let pricingRulesCache: PricingRule[] | null = null;

export interface AddonService {
  id: string;
  title: string;
  price: number;
  pricingType: 'flat' | 'daily';
  description: string;
}

/**
 * Fetch pricing rules from the Pricing Configuration project
 */
export async function fetchPricingRules(): Promise<PricingRule[]> {
  if (pricingRulesCache) {
    return pricingRulesCache;
  }

  try {
    const response = await axios.get('/api/taskade/projects/YCeDMdpmbuM8oejT/nodes');

    if (response.data.ok && response.data.payload?.nodes) {
      const nodes = response.data.payload.nodes;

      pricingRulesCache = nodes
        .filter((node: any) => node.parentId === null) // Only root-level nodes
        .map((node: any) => {
          const categoryValue = node.fieldValues?.['/attributes/@ctgry'];
          const pricingTypeValue = node.fieldValues?.['/attributes/@prcng'];

          // Map select option IDs to readable values
          const categoryMap: Record<string, 'base' | 'surcharge' | 'addon' | 'peak'> = {
            'cat-base': 'base',
            'cat-surcharge': 'surcharge',
            'cat-addon': 'addon',
            'cat-peak': 'peak'
          };

          const pricingTypeMap: Record<string, 'flat' | 'daily' | 'hourly'> = {
            'prc-flat': 'flat',
            'prc-daily': 'daily',
            'prc-hourly': 'hourly'
          };

          return {
            id: node.id,
            title: node.fieldValues?.['/text'] || '',
            duration: node.fieldValues?.['/attributes/@dur8n'] || '',
            price: node.fieldValues?.['/attributes/@pr1ce'] || 0,
            active: node.fieldValues?.['/attributes/@activ'] === 'opt-yes',
            category: categoryMap[categoryValue] || 'base',
            pricingType: pricingTypeMap[pricingTypeValue] || 'flat',
            description: node.fieldValues?.['/attributes/@descr'] || ''
          };
        })
        .filter((rule: PricingRule) => rule.active); // Only active rules

      return pricingRulesCache;
    }

    return [];
  } catch (error) {
    console.error('Failed to fetch pricing rules:', error);
    return [];
  }
}

/**
 * Fetch add-on services from pricing configuration
 */
export async function fetchAddonServices(): Promise<AddonService[]> {
  const rules = await fetchPricingRules();

  return rules
    .filter(rule => rule.category === 'addon')
    .map(rule => ({
      id: rule.id,
      title: rule.title,
      price: rule.price,
      pricingType: rule.pricingType === 'daily' ? 'daily' : 'flat',
      description: rule.description
    }));
}

/**
 * Smart matching function that recognizes descriptive duration values
 * Maps logical pricing categories to actual Duration descriptions in the project
 */
function findBestPricingRule(rules: PricingRule[], category: string): PricingRule | null {
  // Define smart matching patterns for each category
  const patterns: Record<string, (duration: string, title: string) => boolean> = {
    'daycare': (d, t) => 
      (d.toLowerCase().includes('8am-10am') || d.toLowerCase().includes('day-care')) ||
      (t.toLowerCase().includes('day-care only')),

    'overnight': (d, t) => 
      (d.toLowerCase().includes('7pm') && d.toLowerCase().includes('10am')) ||
      (t.toLowerCase().includes('overnight') && t.toLowerCase().includes('only')),

    'full_day': (d, t) => 
      (d.toLowerCase().includes('8am') && d.toLowerCase().includes('24')) ||
      (t.toLowerCase().includes('full day')),

    'extra_daycare': (d, t) =>
      (d.toLowerCase().includes('following overnight') || d.toLowerCase().includes('until 7pm')) ||
      (t.toLowerCase().includes('extra day-care')),

    'early_7am': (d, t) => 
      (d.toLowerCase().includes('7:00') && d.toLowerCase().includes('7:59')) ||
      (t.toLowerCase().includes('7:00am - 7:59am')),

    'early_6am': (d, t) => 
      (d.toLowerCase().includes('6:00') && d.toLowerCase().includes('6:59')) ||
      (t.toLowerCase().includes('6:00am - 6:59am')),

    'early_before_6am': (d, t) => 
      (d.toLowerCase().includes('before 6')) ||
      (t.toLowerCase().includes('before 6')),

    'late_hourly': (d, t) => 
      (d.toLowerCase().includes('per hour') && t.toLowerCase().includes('late')) ||
      (t.toLowerCase().includes('late pick-up hourly')),

    'peak_christmas': (d, t) => 
      (d.toLowerCase().includes('christmas') || d.toLowerCase().includes('dec 23')) ||
      (t.toLowerCase().includes('christmas') || t.toLowerCase().includes('tier 1')),

    'peak_easter': (d, t) =>
      (d.toLowerCase().includes('easter') || d.toLowerCase().includes('herbstferien')) ||
      (t.toLowerCase().includes('tier 2'))
  };

  const matcher = patterns[category];
  if (!matcher) return null;

  return rules.find(rule => matcher(rule.duration.toLowerCase(), rule.title.toLowerCase())) || null;
}

/**
 * Calculate pricing for dog boarding based on drop-off and pick-up times
 * This is the single source of truth for all pricing calculations
 */
export async function calculatePricing(input: PricingInput): Promise<PricingBreakdown> {
  const { dropoffDate, dropoffTime, pickupDate, pickupTime } = input;

  // Fetch pricing rules from the project
  const pricingRules = await fetchPricingRules();

  const dropoff = parseISO(`${dropoffDate}T${dropoffTime}`);
  const pickup = parseISO(`${pickupDate}T${pickupTime}`);

  const dropoffHour = dropoff.getHours();
  const pickupHour = pickup.getHours();

  // Calculate the "normalized" 8am-to-8am periods
  const normalizedDropoff = new Date(dropoff);
  if (dropoffHour < 8) {
    normalizedDropoff.setHours(8, 0, 0, 0);
  }

  const normalizedPickup = new Date(pickup);

  // Calculate total hours from normalized drop-off to pick-up
  const totalHours = differenceInHours(normalizedPickup, normalizedDropoff);

  // Calculate number of full 24h periods (8am to 8am)
  const full24hPeriods = Math.floor(totalHours / 24);
  const remainingHours = totalHours % 24;

  let basePrice = 0;
  let basePriceLabel = '';

  // Calculate base pricing based on 8am-to-8am periods
  if (full24hPeriods === 0 && remainingHours <= 12 && dropoffHour >= 8 && dropoffHour <= 10) {
    // Day-care only (8am-10am drop, up to 12h)
    const rule = findBestPricingRule(pricingRules, 'daycare');
    basePrice = rule?.price || 30;
    basePriceLabel = rule?.title || 'Day-care only (up to 12h)';
  } else if (full24hPeriods === 0 && dropoffHour >= 19 && pickupHour <= 10) {
    // Overnight only (7pm to 10am)
    const rule = findBestPricingRule(pricingRules, 'overnight');
    basePrice = rule?.price || 25;
    basePriceLabel = rule?.title || 'Overnight only';
  } else if (full24hPeriods === 0 && remainingHours <= 24) {
    // Single 24h period
    const rule = findBestPricingRule(pricingRules, 'full_day');
    basePrice = rule?.price || 35;
    basePriceLabel = rule?.title || 'Full day + overnight (up to 24h)';
  } else {
    // Multi-day stay
    const fullDayRule = findBestPricingRule(pricingRules, 'full_day');
    const fullDayPrice = fullDayRule?.price || 35;

    // First 24h period
    basePrice = fullDayPrice;

    // Additional full 24h periods
    for (let i = 1; i < full24hPeriods; i++) {
      basePrice += fullDayPrice;
    }

    // Remaining hours after last 8am
    if (remainingHours > 0) {
      if (remainingHours <= 11) {
        // Extra day-care (up to 11 hours, until 7pm)
        const extraDaycareRule = findBestPricingRule(pricingRules, 'extra_daycare');
        basePrice += extraDaycareRule?.price || 25;
        basePriceLabel = `${full24hPeriods} full day(s) + extra day-care`;
      } else {
        // Another full day if more than 11 hours
        basePrice += fullDayPrice;
        basePriceLabel = `${full24hPeriods + 1} full day(s)`;
      }
    } else {
      basePriceLabel = `${full24hPeriods} full day(s)`;
    }
  }

  // Early drop-off surcharge (applied if drop-off is before 8am)
  let earlyDropoffSurcharge = 0;
  let earlyDropoffLabel = '';

  if (dropoffHour >= 7 && dropoffHour < 8) {
    const rule = findBestPricingRule(pricingRules, 'early_7am');
    earlyDropoffSurcharge = rule?.price || 3;
    earlyDropoffLabel = rule?.title || '7:00am - 7:59am drop-off';
  } else if (dropoffHour >= 6 && dropoffHour < 7) {
    const rule = findBestPricingRule(pricingRules, 'early_6am');
    earlyDropoffSurcharge = rule?.price || 5;
    earlyDropoffLabel = rule?.title || '6:00am - 6:59am drop-off';
  } else if (dropoffHour < 6) {
    const rule = findBestPricingRule(pricingRules, 'early_before_6am');
    earlyDropoffSurcharge = rule?.price || 10;
    earlyDropoffLabel = rule?.title || 'Before 6:00am drop-off';
  }

  // Late pick-up fee ($3/hour after 6pm)
  let latePickupFee = 0;
  let latePickupLabel = '';

  // Calculate the expected 6pm (18:00) pick-up time on the final day
  const expectedPickupDate = new Date(normalizedDropoff);
  expectedPickupDate.setDate(expectedPickupDate.getDate() + full24hPeriods);
  expectedPickupDate.setHours(18, 0, 0, 0);

  // If pick-up is after 6pm, calculate late fee
  if (pickup > expectedPickupDate) {
    const lateHours = Math.ceil(differenceInHours(pickup, expectedPickupDate));
    const hourlyLateRule = findBestPricingRule(pricingRules, 'late_hourly');
    const hourlyRate = hourlyLateRule?.price || 3;
    const lateFeeAmount = lateHours * hourlyRate;

    const daycareRule = findBestPricingRule(pricingRules, 'daycare');
    const daycarePrice = daycareRule?.price || 25;

    // After 8 hours, switch to day care rate for better value
    if (lateHours >= 8) {
      // If we haven't already charged for extra day-care, add it now
      if (remainingHours === 0 || remainingHours > 11) {
        latePickupFee = daycarePrice;
        latePickupLabel = 'Extra day-care (late pickup)';
      }
    } else if (lateHours > 0) {
      // Charge hourly rate for less than 8 hours
      latePickupFee = lateFeeAmount;
      latePickupLabel = `${lateHours}h late pick-up (after 6pm)`;
    }
  }

  // Peak period surcharge
  let peakPeriodSurcharge = 0;
  let peakPeriodLabel = '';

  const dropoffMonth = dropoff.getMonth();
  const dropoffDay = dropoff.getDate();

  // Christmas/New Year (Dec 23 - Jan 6)
  const isChristmasPeriod = (dropoffMonth === 11 && dropoffDay >= 23) || (dropoffMonth === 0 && dropoffDay <= 6);

  if (isChristmasPeriod) {
    const totalDays = full24hPeriods + (remainingHours > 0 ? 1 : 0);
    const peakRule = findBestPricingRule(pricingRules, 'peak_christmas');
    const dailyPeakFee = peakRule?.price || 5;
    peakPeriodSurcharge = totalDays * dailyPeakFee;
    peakPeriodLabel = peakRule?.title || 'Christmas/New Year period';
  }

  const totalPrice = basePrice + earlyDropoffSurcharge + latePickupFee + peakPeriodSurcharge;

  return {
    basePrice,
    basePriceLabel,
    earlyDropoffSurcharge,
    earlyDropoffLabel,
    latePickupFee,
    latePickupLabel,
    peakPeriodSurcharge,
    peakPeriodLabel,
    totalPrice
  };
}

/**
 * Format pricing breakdown into a readable string
 */
export function formatPricingBreakdown(breakdown: PricingBreakdown): string {
  const items: string[] = [];

  if (breakdown.basePrice > 0) {
    items.push(`${breakdown.basePriceLabel}: ${breakdown.basePrice}`);
  }

  if (breakdown.earlyDropoffSurcharge > 0) {
    items.push(`${breakdown.earlyDropoffLabel}: ${breakdown.earlyDropoffSurcharge}`);
  }

  if (breakdown.latePickupFee > 0) {
    items.push(`${breakdown.latePickupLabel}: ${breakdown.latePickupFee}`);
  }

  if (breakdown.peakPeriodSurcharge > 0) {
    items.push(`${breakdown.peakPeriodLabel}: ${breakdown.peakPeriodSurcharge}`);
  }

  return items.join('\n');
}

import * as React from "react"

const MOBILE_BREAKPOINT = 768

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined)

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`)
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    }
    mql.addEventListener("change", onChange)
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    return () => mql.removeEventListener("change", onChange)
  }, [])

  return !!isMobile
}

