import { motion, AnimatePresence } from 'framer-motion';
import { format } from 'date-fns';
import { toast } from 'sonner';
import axios from 'axios';
import { calculatePricing, fetchAddonServices, fetchPricingRules, type PricingBreakdown, type AddonService } from '../lib/pricing';

export const PricingCalculator: React.FC = () => {
  // Helper function to get dates relative to today
  const getDefaultDates = () => {
    const today = new Date();
    const dropoff = new Date(today);
    dropoff.setDate(today.getDate() + 7); // One week from now
    const pickup = new Date(dropoff);
    pickup.setDate(dropoff.getDate() + 3); // 3-night stay

    return {
      dropoffDate: dropoff.toISOString().split('T')[0],
      pickupDate: pickup.toISOString().split('T')[0]
    };
  };

  const defaultDates = getDefaultDates();

  const [dropoffDate, setDropoffDate] = React.useState(defaultDates.dropoffDate);
  const [dropoffTime, setDropoffTime] = React.useState('09:30');
  const [pickupDate, setPickupDate] = React.useState(defaultDates.pickupDate);
  const [pickupTime, setPickupTime] = React.useState('16:00');
  const [customerName, setCustomerName] = React.useState('Sarah Mitchell');
  const [customerEmail, setCustomerEmail] = React.useState('sarah.mitchell@email.com');
  const [customerPhone, setCustomerPhone] = React.useState('+1 (555) 234-5678');
  const [petName, setPetName] = React.useState('Charlie');
  const [petType, setPetType] = React.useState<'dog' | 'cat' | 'other'>('dog');
  const [petAge, setPetAge] = React.useState('4 years');
  const [petBreed, setPetBreed] = React.useState('Golden Retriever');
  const [medicalConditions, setMedicalConditions] = React.useState('None. Charlie is healthy and up to date on all vaccinations.');
  const [feedingInstructions, setFeedingInstructions] = React.useState('2 cups of dry food twice daily (morning and evening). Fresh water always available. Charlie also gets a small dental chew after dinner.');
  const [emergencyContact, setEmergencyContact] = React.useState('Michael Mitchell');
  const [emergencyPhone, setEmergencyPhone] = React.useState('+1 (555) 876-5432');
  const [specialNotes, setSpecialNotes] = React.useState('Charlie loves playing fetch and gets excited around other dogs. He sleeps with his favorite blue squeaky toy. Prefers belly rubs over treats!');
  const [isSubmitting, setIsSubmitting] = React.useState(false);
  const [addonServices, setAddonServices] = React.useState<AddonService[]>([]);
  const [selectedAddons, setSelectedAddons] = React.useState<Record<string, boolean>>({
    // These IDs will be populated once addonServices loads
    // We'll set them in a useEffect once we know the actual IDs
  });
  const [pricing, setPricing] = React.useState<PricingBreakdown | null>(null);
  const [isCalculatingPrice, setIsCalculatingPrice] = React.useState(false);
  const [pricingRules, setPricingRules] = React.useState<any[]>([]);
  const [isPricingGuideExpanded, setIsPricingGuideExpanded] = React.useState(false);

  // Fetch add-on services and pricing rules on mount
  React.useEffect(() => {
    const loadPricingData = async () => {
      const [services, rules] = await Promise.all([
        fetchAddonServices(),
        fetchPricingRules()
      ]);
      setAddonServices(services);
      setPricingRules(rules);

      // Auto-select first two add-on services for demo
      if (services.length >= 2) {
        setSelectedAddons({
          [services[0].id]: true,
          [services[1].id]: true
        });
      }
    };
    loadPricingData();
  }, []);

  // Calculate pricing whenever relevant fields change
  React.useEffect(() => {
    const calculatePricingWrapper = async () => {
      if (!dropoffDate || !pickupDate) {
        setPricing(null);
        return;
      }

      setIsCalculatingPrice(true);
      try {
        const result = await calculatePricing({
          dropoffDate,
          dropoffTime,
          pickupDate,
          pickupTime
        });
        setPricing(result);
      } catch (error) {
        console.error('Failed to calculate pricing:', error);
        setPricing(null);
      } finally {
        setIsCalculatingPrice(false);
      }
    };

    calculatePricingWrapper();
  }, [dropoffDate, dropoffTime, pickupDate, pickupTime]);

  const handleSubmitQuote = async () => {
    if (!customerName || !customerEmail || !customerPhone || !petName || !dropoffDate || !pickupDate || !pricing) {
      toast.error('Please fill in all required fields');
      return;
    }

    setIsSubmitting(true);

    try {
      // Create proper datetime with time included
      const dropoffDateTime = `${dropoffDate}T${dropoffTime}:00`;
      const pickupDateTime = `${pickupDate}T${pickupTime}:00`;

      // Calculate number of nights
      const checkInDate = new Date(dropoffDate);
      const checkOutDate = new Date(pickupDate);
      const nights = Math.ceil((checkOutDate.getTime() - checkInDate.getTime()) / (1000 * 60 * 60 * 24));

      // Calculate additional services total with daily pricing support
      let additionalServicesTotal = 0;
      const servicesList: string[] = [];

      Object.keys(selectedAddons).forEach(serviceId => {
        if (selectedAddons[serviceId]) {
          const service = addonServices.find(s => s.id === serviceId);
          if (service) {
            const servicePrice = service.pricingType === 'daily' 
              ? service.price * nights 
              : service.price;
            additionalServicesTotal += servicePrice;
            servicesList.push(service.title);
          }
        }
      });

      const finalTotal = pricing.totalPrice + additionalServicesTotal;

      // Combine special notes
      const allNotes = [
        specialNotes,
        petAge ? `Age: ${petAge}` : '',
        petBreed ? `Breed: ${petBreed}` : '',
        medicalConditions ? `Medical: ${medicalConditions}` : '',
        feedingInstructions ? `Feeding: ${feedingInstructions}` : '',
        emergencyContact ? `Emergency Contact: ${emergencyContact} (${emergencyPhone})` : ''
      ].filter(Boolean).join(' | ');

      // Create full datetime strings in ISO format with timezone
      const dropoffFullDateTime = new Date(`${dropoffDate}T${dropoffTime}`).toISOString();
      const pickupFullDateTime = new Date(`${pickupDate}T${pickupTime}`).toISOString();

      await axios.post('/api/taskade/projects/QHKG3Y96ZqGwQD1p/nodes', {
        '/text': `${customerName} - ${petName} (${format(checkInDate, 'MMM d')} - ${format(checkOutDate, 'MMM d')})`,
        '/attributes/@cName': customerName,
        '/attributes/@cEmail': customerEmail,
        '/attributes/@cPhone': customerPhone,
        '/attributes/@petName': petName,
        '/attributes/@petType': petType,
        '/attributes/@checkIn': dropoffFullDateTime,
        '/attributes/@checkOut': pickupFullDateTime,
        '/attributes/@nights': nights,
        '/attributes/@basePrice': pricing.basePrice,
        '/attributes/@totalPrice': finalTotal,
        '/attributes/@addOns': servicesList.length > 0 ? servicesList.join(', ') : 'None',
        '/attributes/@status': 'new',
        '/attributes/@notes': allNotes,
        '/attributes/note': `Quote request for ${petName}. Drop-off: ${format(checkInDate, 'PPP')} at ${dropoffTime}, Pick-up: ${format(checkOutDate, 'PPP')} at ${pickupTime}.`
      });

      toast.success('🎉 Quote saved successfully!', {
        description: `Your ${nights}-night booking request for ${petName} has been submitted. Total: ${finalTotal.toFixed(2)}`
      });

      // Reset form
      setCustomerName('');
      setCustomerEmail('');
      setCustomerPhone('');
      setPetName('');
      setPetType('dog');
      setPetAge('');
      setPetBreed('');
      setMedicalConditions('');
      setFeedingInstructions('');
      setEmergencyContact('');
      setEmergencyPhone('');
      setSpecialNotes('');
      setDropoffDate('');
      setPickupDate('');
      setSelectedAddons({});
    } catch (error: any) {
      console.error('Error submitting quote:', error);
      const errorMessage = error?.response?.data?.message || error?.message || 'Unknown error occurred';
      toast.error('Failed to submit quote', {
        description: errorMessage
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const hasValidDates = dropoffDate && pickupDate;

  return (
    <div className="w-full">
      <div className="overflow-y-auto px-6 py-8 space-y-5 max-h-[calc(100vh-300px)]">
        {/* Pet Information */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="bg-stone-50/50 border border-stone-200/50 rounded-2xl p-5"
        >
          <h3 className="text-sm font-semibold text-stone-800 mb-4 flex items-center gap-2 uppercase tracking-wide">
            <Dog className="w-4 h-4 text-stone-600" />
            Pet Information
          </h3>

          <div className="space-y-3">
            {/* Pet Name */}
            <div>
              <label className="block text-sm font-medium text-stone-700 mb-2">
                Pet's Name <span className="text-red-500">*</span>
              </label>
              <input
                type="text"
                value={petName}
                onChange={(e) => setPetName(e.target.value)}
                placeholder="Fluffy"
                className="w-full px-4 py-3 bg-white border border-stone-300 rounded-xl text-stone-900 placeholder-stone-400 focus:outline-none focus:ring-2 focus:ring-amber-500/50"
              />
            </div>

            {/* Pet Type & Age */}
            <div className="grid md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-stone-700 mb-2">
                  Pet Type
                </label>
                <select
                  value={petType}
                  onChange={(e) => setPetType(e.target.value as 'dog' | 'cat' | 'other')}
                  className="w-full px-4 py-3 bg-white border border-stone-300 rounded-xl text-stone-900 focus:outline-none focus:ring-2 focus:ring-amber-500/50"
                >
                  <option value="dog">Dog</option>
                  <option value="cat">Cat</option>
                  <option value="other">Other</option>
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-stone-700 mb-2">
                  Age
                </label>
                <input
                  type="text"
                  value={petAge}
                  onChange={(e) => setPetAge(e.target.value)}
                  placeholder="e.g., 3 years"
                  className="w-full px-4 py-3 bg-white border border-stone-300 rounded-xl text-stone-900 placeholder-stone-400 focus:outline-none focus:ring-2 focus:ring-amber-500/50"
                />
              </div>
            </div>

            {/* Breed */}
            <div>
              <label className="block text-sm font-medium text-stone-700 mb-2">
                Breed
              </label>
              <input
                type="text"
                value={petBreed}
                onChange={(e) => setPetBreed(e.target.value)}
                placeholder="e.g., Golden Retriever"
                className="w-full px-4 py-3 bg-white border border-stone-300 rounded-xl text-stone-900 placeholder-stone-400 focus:outline-none focus:ring-2 focus:ring-amber-500/50"
              />
            </div>

            {/* Medical Conditions */}
            <div>
              <label className="block text-sm font-medium text-stone-700 mb-2">
                Medical Conditions or Allergies
              </label>
              <textarea
                value={medicalConditions}
                onChange={(e) => setMedicalConditions(e.target.value)}
                placeholder="Please list any medical conditions, medications, or allergies..."
                rows={3}
                className="w-full px-4 py-3 bg-white border border-stone-300 rounded-xl text-stone-900 placeholder-stone-400 focus:outline-none focus:ring-2 focus:ring-amber-500/50 resize-none"
              />
            </div>

            {/* Feeding Instructions */}
            <div>
              <label className="block text-sm font-medium text-stone-700 mb-2">
                Feeding Instructions
              </label>
              <textarea
                value={feedingInstructions}
                onChange={(e) => setFeedingInstructions(e.target.value)}
                placeholder="e.g., 2 cups dry food twice daily, morning and evening..."
                rows={3}
                className="w-full px-4 py-3 bg-white border border-stone-300 rounded-xl text-stone-900 placeholder-stone-400 focus:outline-none focus:ring-2 focus:ring-amber-500/50 resize-none"
              />
            </div>

            {/* Special Notes */}
            <div>
              <label className="block text-sm font-medium text-stone-700 mb-2">
                Special Notes or Instructions
              </label>
              <textarea
                value={specialNotes}
                onChange={(e) => setSpecialNotes(e.target.value)}
                placeholder="Anything else we should know? Favorite toys, quirks, fears, etc..."
                rows={3}
                className="w-full px-4 py-3 bg-white border border-stone-300 rounded-xl text-stone-900 placeholder-stone-400 focus:outline-none focus:ring-2 focus:ring-amber-500/50 resize-none"
              />
            </div>
          </div>
        </motion.div>

        {/* Date & Time Selection */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.2 }}
          className="bg-stone-50/50 border border-stone-200/50 rounded-2xl p-5"
        >
          <h3 className="text-sm font-semibold text-stone-800 mb-4 flex items-center gap-2 uppercase tracking-wide">
            <Calendar className="w-4 h-4 text-stone-600" />
            Select Dates & Times
          </h3>

          <div className="grid md:grid-cols-2 gap-4">
            {/* Drop-off */}
            <div className="space-y-3">
              <label className="block text-sm font-medium text-stone-700">
                Drop-off Date
              </label>
              <input
                type="date"
                value={dropoffDate}
                onChange={(e) => setDropoffDate(e.target.value)}
                className="w-full px-4 py-3 bg-white border border-stone-300 rounded-xl text-stone-900 focus:outline-none focus:ring-2 focus:ring-amber-500/50"
              />
              <div className="flex items-center gap-2">
                <Clock className="w-4 h-4 text-stone-500" />
                <input
                  type="time"
                  value={dropoffTime}
                  onChange={(e) => setDropoffTime(e.target.value)}
                  className="flex-1 px-4 py-3 bg-white border border-stone-300 rounded-xl text-stone-900 focus:outline-none focus:ring-2 focus:ring-amber-500/50"
                />
              </div>
            </div>

            {/* Pick-up */}
            <div className="space-y-3">
              <label className="block text-sm font-medium text-stone-700">
                Pick-up Date
              </label>
              <input
                type="date"
                value={pickupDate}
                onChange={(e) => setPickupDate(e.target.value)}
                className="w-full px-4 py-3 bg-white border border-stone-300 rounded-xl text-stone-900 focus:outline-none focus:ring-2 focus:ring-amber-500/50"
              />
              <div className="flex items-center gap-2">
                <Clock className="w-4 h-4 text-stone-500" />
                <input
                  type="time"
                  value={pickupTime}
                  onChange={(e) => setPickupTime(e.target.value)}
                  className="flex-1 px-4 py-3 bg-white border border-stone-300 rounded-xl text-stone-900 focus:outline-none focus:ring-2 focus:ring-amber-500/50"
                />
              </div>
            </div>
          </div>
        </motion.div>

        {/* Additional Services */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.35 }}
          className="bg-stone-50/50 border border-stone-200/50 rounded-2xl p-5"
        >
          <h3 className="text-sm font-semibold text-stone-800 mb-2 flex items-center gap-2 uppercase tracking-wide">
            <Sparkles className="w-4 h-4 text-stone-600" />
            Additional Services
          </h3>
          <p className="text-xs text-stone-500 mb-3">Enhance your pet's stay with our premium services</p>

          <div className="space-y-3">
            {addonServices.map((service, index) => {
              const isSelected = selectedAddons[service.id] || false;
              const colorSchemes = [
                { bg: 'from-amber-100/60', border: 'border-amber-200 hover:border-amber-300', checkbox: 'text-amber-600 focus:ring-amber-500/50' },
                { bg: 'from-orange-100/60', border: 'border-orange-200 hover:border-orange-300', checkbox: 'text-orange-600 focus:ring-orange-500/50' },
                { bg: 'from-stone-200/60', border: 'border-stone-300 hover:border-stone-400', checkbox: 'text-stone-600 focus:ring-stone-500/50' },
                { bg: 'from-rose-100/60', border: 'border-rose-200 hover:border-rose-300', checkbox: 'text-rose-600 focus:ring-rose-500/50' }
              ];
              const colorScheme = colorSchemes[index % colorSchemes.length];

              // Calculate nights for display
              const checkInDate = dropoffDate ? new Date(dropoffDate) : null;
              const checkOutDate = pickupDate ? new Date(pickupDate) : null;
              const hasValidNights = checkInDate && checkOutDate;
              const nights = checkInDate && checkOutDate 
                ? Math.ceil((checkOutDate.getTime() - checkInDate.getTime()) / (1000 * 60 * 60 * 24))
                : 1;

              const displayPrice = service.pricingType === 'daily' && hasValidNights
                ? `+${(service.price * nights).toFixed(2)} (${nights}d × ${service.price})`
                : `+${service.price.toFixed(2)}${service.pricingType === 'daily' ? '/day' : ''}`;

              return (
                <motion.div
                  key={service.id}
                  whileHover={{ scale: 1.02 }}
                  className={`flex items-center gap-3 p-4 bg-gradient-to-r ${colorScheme.bg} to-transparent rounded-xl border ${colorScheme.border} transition-all cursor-pointer`}
                  onClick={() => setSelectedAddons(prev => ({ ...prev, [service.id]: !prev[service.id] }))}
                >
                  <input
                    type="checkbox"
                    checked={isSelected}
                    onChange={(e) => setSelectedAddons(prev => ({ ...prev, [service.id]: e.target.checked }))}
                    className={`w-5 h-5 rounded border-stone-300 ${colorScheme.checkbox} focus:ring-2`}
                    onClick={(e) => e.stopPropagation()}
                  />
                  <div className="flex-1">
                    <p className="text-stone-900 font-medium">{service.title}</p>
                    <p className="text-xs text-stone-600 mt-0.5">{service.description}</p>
                  </div>
                  <span className="text-amber-700 font-semibold text-sm">{displayPrice}</span>
                </motion.div>
              );
            })}
          </div>
        </motion.div>

        {/* Pricing Breakdown */}
        <AnimatePresence>
          {isCalculatingPrice && (
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
              className="backdrop-blur-lg bg-gradient-to-br from-amber-50 to-stone-100 border border-amber-200 rounded-2xl p-6 shadow-lg"
            >
              <div className="flex items-center justify-center gap-3 py-8">
                <Loader2 className="w-6 h-6 text-amber-700 animate-spin" />
                <p className="text-stone-600">Calculating your quote...</p>
              </div>
            </motion.div>
          )}
          {!isCalculatingPrice && pricing && (
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
              className="bg-stone-50/70 border border-stone-200/60 rounded-2xl p-5"
            >
              <h3 className="text-sm font-semibold text-stone-800 mb-4 flex items-center gap-2 uppercase tracking-wide">
                <DollarSign className="w-4 h-4 text-stone-600" />
                Price Calculation
              </h3>

              {/* Full Calculation Table */}
              <div className="bg-white rounded-xl border border-amber-200 overflow-hidden">
                <table className="w-full">
                  <thead>
                    <tr className="bg-amber-100">
                      <th className="text-left px-4 py-3 text-sm font-semibold text-stone-900">Item</th>
                      <th className="text-right px-4 py-3 text-sm font-semibold text-stone-900">Amount</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-stone-200">
                    {/* Base Price */}
                    <tr className="hover:bg-stone-50 transition-colors">
                      <td className="px-4 py-3">
                        <p className="text-stone-900 font-medium">{pricing.basePriceLabel}</p>
                        <p className="text-xs text-stone-500 mt-0.5">Core boarding service</p>
                      </td>
                      <td className="px-4 py-3 text-right">
                        <span className="text-stone-900 font-semibold">${pricing.basePrice.toFixed(2)}</span>
                      </td>
                    </tr>

                    {/* Early Drop-off */}
                    {pricing.earlyDropoffSurcharge > 0 && (
                      <tr className="hover:bg-stone-50 transition-colors">
                        <td className="px-4 py-3">
                          <p className="text-stone-700">{pricing.earlyDropoffLabel}</p>
                          <p className="text-xs text-stone-500 mt-0.5">Early access surcharge</p>
                        </td>
                        <td className="px-4 py-3 text-right">
                          <span className="text-amber-600">+${pricing.earlyDropoffSurcharge.toFixed(2)}</span>
                        </td>
                      </tr>
                    )}

                    {/* Late Pick-up */}
                    {pricing.latePickupFee > 0 && (
                      <tr className="hover:bg-stone-50 transition-colors">
                        <td className="px-4 py-3">
                          <p className="text-stone-700">{pricing.latePickupLabel}</p>
                          <p className="text-xs text-stone-500 mt-0.5">Extended care fee</p>
                        </td>
                        <td className="px-4 py-3 text-right">
                          <span className="text-amber-600">+${pricing.latePickupFee.toFixed(2)}</span>
                        </td>
                      </tr>
                    )}

                    {/* Peak Period */}
                    {pricing.peakPeriodSurcharge > 0 && (
                      <tr className="hover:bg-stone-50 transition-colors">
                        <td className="px-4 py-3">
                          <p className="text-stone-700">{pricing.peakPeriodLabel}</p>
                          <p className="text-xs text-stone-500 mt-0.5">Holiday season adjustment</p>
                        </td>
                        <td className="px-4 py-3 text-right">
                          <span className="text-amber-600">+${pricing.peakPeriodSurcharge.toFixed(2)}</span>
                        </td>
                      </tr>
                    )}

                    {/* Subtotal (if there are surcharges) */}
                    {(pricing.earlyDropoffSurcharge > 0 || pricing.latePickupFee > 0 || 
                      pricing.peakPeriodSurcharge > 0) && (
                      <tr className="bg-stone-50 font-medium">
                        <td className="px-4 py-3">
                          <p className="text-stone-900">Boarding Subtotal</p>
                        </td>
                        <td className="px-4 py-3 text-right">
                          <span className="text-stone-900">${pricing.totalPrice.toFixed(2)}</span>
                        </td>
                      </tr>
                    )}

                    {/* Additional Services Section */}
                    {Object.keys(selectedAddons).some(id => selectedAddons[id]) && (
                      <tr className="bg-amber-50">
                        <td colSpan={2} className="px-4 py-2">
                          <p className="text-xs font-semibold text-amber-900 uppercase tracking-wide">Add-On Services</p>
                        </td>
                      </tr>
                    )}

                    {addonServices.map(service => {
                      const isSelected = selectedAddons[service.id];
                      if (!isSelected) return null;

                      const checkInDate = new Date(dropoffDate);
                      const checkOutDate = new Date(pickupDate);
                      const nights = Math.ceil((checkOutDate.getTime() - checkInDate.getTime()) / (1000 * 60 * 60 * 24));
                      const servicePrice = service.pricingType === 'daily' ? service.price * nights : service.price;
                      const priceLabel = service.pricingType === 'daily' 
                        ? `+${servicePrice.toFixed(2)} (${nights}d × ${service.price})` 
                        : `+${servicePrice.toFixed(2)}`;

                      return (
                        <tr key={service.id} className="hover:bg-stone-50 transition-colors">
                          <td className="px-4 py-3">
                            <p className="text-stone-700">{service.title}</p>
                            <p className="text-xs text-stone-500 mt-0.5">{service.description}</p>
                          </td>
                          <td className="px-4 py-3 text-right">
                            <span className="text-amber-600">{priceLabel}</span>
                          </td>
                        </tr>
                      );
                    })}

                    {/* Grand Total */}
                    <tr className="bg-gradient-to-r from-amber-100 to-amber-50">
                      <td className="px-4 py-4">
                        <p className="text-lg font-bold text-stone-900">Total Price</p>
                        <p className="text-xs text-stone-600 mt-0.5">All services included</p>
                      </td>
                      <td className="px-4 py-4 text-right">
                        <span className="text-2xl font-bold text-amber-700">
                          ${(() => {
                            const checkInDate = new Date(dropoffDate);
                            const checkOutDate = new Date(pickupDate);
                            const nights = Math.ceil((checkOutDate.getTime() - checkInDate.getTime()) / (1000 * 60 * 60 * 24));
                            let addonsTotal = 0;
                            Object.keys(selectedAddons).forEach(serviceId => {
                              if (selectedAddons[serviceId]) {
                                const service = addonServices.find(s => s.id === serviceId);
                                if (service) {
                                  addonsTotal += service.pricingType === 'daily' ? service.price * nights : service.price;
                                }
                              }
