import * as React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import axios from 'axios';
import { Calendar, Clock, DollarSign, Loader2, CheckCircle2 } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { calculatePricing } from './lib/pricing';

const bookingSchema = z.object({
  customerName: z.string().min(2, 'Name must be at least 2 characters'),
  email: z.string().email('Invalid email address'),
  phone: z.string().min(10, 'Phone number must be at least 10 digits'),
  petName: z.string().min(1, 'Pet name is required'),
  dropoffDate: z.string().min(1, 'Drop-off date is required'),
  dropoffTime: z.string().min(1, 'Drop-off time is required'),
  pickupDate: z.string().min(1, 'Pick-up date is required'),
  pickupTime: z.string().min(1, 'Pick-up time is required'),
  needsConstantCompany: z.boolean(),
  addGrooming: z.boolean(),
  addTraining: z.boolean(),
  addWalking: z.boolean(),
  specialNotes: z.string().optional(),
});

type BookingFormData = z.infer<typeof bookingSchema>;

export const BookingForm: React.FC = () => {
  const [isCalculating, setIsCalculating] = React.useState(false);
  const [isSubmitting, setIsSubmitting] = React.useState(false);
  const [calculatedPrice, setCalculatedPrice] = React.useState<number | null>(null);
  const [priceBreakdown, setPriceBreakdown] = React.useState<string>('');
  const [isSuccess, setIsSuccess] = React.useState(false);
  const [showQuote, setShowQuote] = React.useState(false);

  const {
    register,
    handleSubmit,
    watch,
    formState: { errors },
    reset,
  } = useForm<BookingFormData>({
    resolver: zodResolver(bookingSchema),
    defaultValues: {
      needsConstantCompany: false,
      addGrooming: false,
      addTraining: false,
      addWalking: false,
    },
  });

  const formValues = watch();

  React.useEffect(() => {
    const hasRequiredFields = formValues.dropoffDate && 
                              formValues.dropoffTime && 
                              formValues.pickupDate && 
                              formValues.pickupTime;

    if (hasRequiredFields) {
      calculatePrice();
    }
  }, [
    formValues.dropoffDate,
    formValues.dropoffTime,
    formValues.pickupDate,
    formValues.pickupTime,
    formValues.needsConstantCompany,
    formValues.addGrooming,
    formValues.addTraining,
    formValues.addWalking,
  ]);

  const calculatePrice = async () => {
    setIsCalculating(true);

    try {
      // Use the shared pricing utility - single source of truth (now async!)
      const pricing = await calculatePricing({
        dropoffDate: formValues.dropoffDate,
        dropoffTime: formValues.dropoffTime,
        pickupDate: formValues.pickupDate,
        pickupTime: formValues.pickupTime,
        aloneTimeBehavior: formValues.needsConstantCompany ? 'alerts' : 'fine'
      });

      // Build breakdown items from pricing result
      const breakdownItems: string[] = [];

      if (pricing.basePrice > 0) {
        breakdownItems.push(`${pricing.basePriceLabel}: €${pricing.basePrice}`);
      }

      if (pricing.earlyDropoffSurcharge > 0) {
        breakdownItems.push(`${pricing.earlyDropoffLabel}: €${pricing.earlyDropoffSurcharge}`);
      }

      if (pricing.latePickupFee > 0) {
        breakdownItems.push(`${pricing.latePickupLabel}: €${pricing.latePickupFee}`);
      }

      if (pricing.peakPeriodSurcharge > 0) {
        breakdownItems.push(`${pricing.peakPeriodLabel}: €${pricing.peakPeriodSurcharge}`);
      }

      if (pricing.constantCompanyFee > 0) {
        breakdownItems.push('Constant company (alerts): €5');
      }

      // Add additional services to pricing
      let additionalServicesTotal = 0;
      if (formValues.addGrooming) {
        breakdownItems.push('Grooming service: $50');
        additionalServicesTotal += 50;
      }
      if (formValues.addTraining) {
        breakdownItems.push('Training session: $75');
        additionalServicesTotal += 75;
      }
      if (formValues.addWalking) {
        breakdownItems.push('Daily walks: $25');
        additionalServicesTotal += 25;
      }

      const finalTotal = pricing.totalPrice + additionalServicesTotal;

      setCalculatedPrice(finalTotal);
      setPriceBreakdown(breakdownItems.join('\n'));
    } catch (error) {
      console.error('Price calculation error:', error);
      toast.error('Failed to calculate price. Please try again.');
    } finally {
      setIsCalculating(false);
    }
  };

  const onSubmit = async (data: BookingFormData) => {
    setIsSubmitting(true);

    try {
      const dropoffDateTime = `${data.dropoffDate}T${data.dropoffTime}:00.000Z`;
      const pickupDateTime = `${data.pickupDate}T${data.pickupTime}:00.000Z`;

      // Build additional services list
      const additionalServices = [];
      if (data.addGrooming) additionalServices.push('Grooming');
      if (data.addTraining) additionalServices.push('Training');
      if (data.addWalking) additionalServices.push('Walking');

      await axios.post('/api/taskade/projects/4aJGwgJX26aj48KB/nodes', {
        '/text': `${data.petName} - ${data.customerName}`,
        '/attributes/note': data.specialNotes || '',
        '/attributes/@cname': data.customerName,
