      setIsSuccess(true);
      toast.success('Booking request submitted successfully!');

      setTimeout(() => {
        reset();
        setCalculatedPrice(null);
        setPriceBreakdown('');
        setIsSuccess(false);
        setShowQuote(false);
      }, 3000);
    } catch (error) {
      console.error('Booking submission error:', error);
      toast.error('Failed to submit booking. Please try again.');
