import * as React from 'react';
import { MessageCircle, X, Send, Loader2 } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import axios from 'axios';
import ReactMarkdown from 'react-markdown';

interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
}

interface ChatAssistantProps {
  fullScreen?: boolean;
}

export const ChatAssistant: React.FC<ChatAssistantProps> = ({ fullScreen = false }) => {
  const [messages, setMessages] = React.useState<Message[]>([]);
  const [input, setInput] = React.useState('');
  const [isLoading, setIsLoading] = React.useState(false);
  const [conversationId, setConversationId] = React.useState<string | null>(null);
  const [eventSource, setEventSource] = React.useState<EventSource | null>(null);
  const messagesEndRef = React.useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  React.useEffect(() => {
    scrollToBottom();
  }, [messages]);

  React.useEffect(() => {
    if (!conversationId) {
      initializeConversation();
    }
  }, []);

  const initializeConversation = async () => {
    try {
      const response = await axios.post('/api/taskade/agents/01KN6YVA6MRZ9WNQ41QPZS3S8D/public-conversations');
      const convoId = response.data.conversationId;
      setConversationId(convoId);

      const es = new EventSource(`/api/taskade/agents/01KN6YVA6MRZ9WNQ41QPZS3S8D/public-conversations/${convoId}/stream`);

      let currentMessageId = '';
      let currentContent = '';

      es.onopen = () => {
        console.log('SSE connection opened');
      };

      es.onmessage = (event) => {
        const data = JSON.parse(event.data);

        switch (data.type) {
          case 'start':
            currentMessageId = data.messageId;
            currentContent = '';
            break;

          case 'text-delta':
            currentContent += data.delta;
            setMessages(prev => {
              const existing = prev.find(m => m.id === currentMessageId);
              if (existing) {
                return prev.map(m => 
                  m.id === currentMessageId 
                    ? { ...m, content: currentContent }
                    : m
                );
              } else {
                return [...prev, { id: currentMessageId, role: 'assistant', content: currentContent }];
              }
            });
            break;

          case 'finish':
            setIsLoading(false);
            break;

          case 'error':
            console.error('SSE error:', data.errorText);
            setIsLoading(false);
            break;
        }
      };

      es.onerror = (error) => {
        console.error('SSE connection error:', error);
        es.close();
      };

      setEventSource(es);
    } catch (error) {
      console.error('Failed to initialize conversation:', error);
    }
  };

  const sendMessage = async () => {
    if (!input.trim() || !conversationId || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      await axios.post(
        `/api/taskade/agents/01KN6YVA6MRZ9WNQ41QPZS3S8D/public-conversations/${conversationId}/messages`,
        { text: input }
      );
    } catch (error) {
      console.error('Failed to send message:', error);
      setIsLoading(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  React.useEffect(() => {
    return () => {
      if (eventSource) {
        eventSource.close();
      }
    };
  }, [eventSource]);

  // Render chat interface
  return (
    <div className="h-full flex flex-col overflow-hidden">
        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-4">
          {messages.length === 0 && (
            <div className="text-center py-12">
              <div className="w-16 h-16 bg-gradient-to-br from-orange-100 to-amber-100 border border-orange-200 rounded-2xl flex items-center justify-center mx-auto mb-4">
                <MessageCircle className="w-8 h-8 text-orange-700" />
              </div>
              <h4 className="text-stone-900 font-semibold mb-2 text-lg">Welcome! Let's get started 👋</h4>
              <p className="text-stone-600 text-sm max-w-md mx-auto mb-6">
                I'll ask you a few questions about your pet's stay, calculate a personalized quote, and help you complete your booking.
              </p>
              <div className="flex flex-wrap gap-2 justify-center max-w-2xl mx-auto">
                <button
                  onClick={() => {
                    setInput("I'd like to book a stay for my dog");
                    setTimeout(() => sendMessage(), 100);
                  }}
                  className="px-4 py-2 bg-stone-100 hover:bg-orange-50 border border-stone-200 rounded-xl text-sm text-stone-700 transition-all"
                >
                  Book a stay
                </button>
                <button
                  onClick={() => {
                    setInput("What are your pricing options?");
                    setTimeout(() => sendMessage(), 100);
                  }}
                  className="px-4 py-2 bg-stone-100 hover:bg-orange-50 border border-stone-200 rounded-xl text-sm text-stone-700 transition-all"
                >
                  Pricing info
                </button>
                <button
                  onClick={() => {
                    setInput("What services do you offer?");
                    setTimeout(() => sendMessage(), 100);
                  }}
                  className="px-4 py-2 bg-stone-100 hover:bg-orange-50 border border-stone-200 rounded-xl text-sm text-stone-700 transition-all"
                >
                  Services offered
                </button>
              </div>
            </div>
          )}

          {messages.map((message) => (
            <motion.div
              key={message.id}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className={`flex ${message.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              <div className={`max-w-[85%] md:max-w-[75%] px-4 py-2.5 rounded-2xl ${message.role === 'user' ? 'bg-gradient-to-br from-orange-500 to-orange-600 text-white' : 'bg-stone-50 text-stone-900 border border-stone-200'}`}>
                {message.role === 'assistant' ? (
                  <div className="text-sm leading-relaxed prose prose-sm prose-stone max-w-none prose-p:my-1 prose-ul:my-1 prose-li:my-0">
                    <ReactMarkdown>{message.content}</ReactMarkdown>
                  </div>
                ) : (
                  <p className="text-sm leading-relaxed">{message.content}</p>
                )}
              </div>
            </motion.div>
          ))}

          {isLoading && (
            <div className="flex justify-start">
              <div className="bg-stone-50 border border-stone-200 px-4 py-2.5 rounded-2xl flex items-center gap-2">
                <Loader2 className="w-4 h-4 text-orange-600 animate-spin" />
                <span className="text-sm text-stone-600">Thinking...</span>
              </div>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>

        <div className="p-4 md:p-6 border-t border-stone-200 bg-stone-50">
          <div className="flex gap-2 md:gap-3">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder="Type your message..."
              className="flex-1 px-4 py-3 bg-white border border-stone-300 rounded-xl text-stone-900 placeholder-stone-400 focus:outline-none focus:ring-2 focus:ring-orange-500/50 text-sm md:text-base"
              disabled={isLoading || !conversationId}
            />
            <button
              onClick={sendMessage}
              disabled={!input.trim() || isLoading || !conversationId}
              className="px-4 md:px-6 py-3 bg-gradient-to-br from-orange-500 to-orange-600 text-white rounded-xl hover:from-orange-600 hover:to-orange-700 transition-all disabled:opacity-50 disabled:cursor-not-allowed font-medium text-sm md:text-base"
            >
              <Send className="w-5 h-5" />
            </button>
          </div>
        </div>
      </div>
    );
};
